INSERT INTO `patientexaminations` VALUES (1,1,1,2,'2026-07-06 00:00:00','Ê buốt nhẹ khi uống nước lạnh','Viêm nướu nhẹ, cao răng nhiều','Cạo vôi răng, hướng dẫn vệ sinh răng miệng','Nước súc miệng Chlorhexidine 7 ngày','Bệnh nhân hợp tác tốt',2,'Răng 16, 26 có mảng bám; nướu viêm nhẹ','Cạo vôi răng định kỳ 6 tháng','2026-08-06 00:00:00',NULL),(2,2,2,3,'2026-07-06 00:00:00','Không hài lòng màu răng và hình dáng răng cửa','Răng cửa xỉn màu, men răng mòn nhẹ','Tư vấn Veneer 4 răng cửa, chụp phim trước điều trị',NULL,'Cần báo giá chi tiết trước khi làm',2,'Răng 11,12,21,22 đổi màu nhẹ','Veneer sứ cao cấp','2026-07-20 00:00:00',NULL),(3,3,3,4,'2026-07-07 00:00:00','Đau nhức răng hàm dưới phải','Viêm tủy răng 46','Điều trị tủy nhiều buổi, trám phục hồi sau điều trị','Ibuprofen khi đau, dùng sau ăn','Đã giải thích quy trình nhiều buổi',2,'Răng 46 sâu lớn, đau khi gõ dọc','Điều trị tủy răng, trám Composite','2026-07-14 00:00:00',NULL),(4,4,4,2,'2026-07-08 00:00:00','Khám lần đầu, hơi chảy máu nướu','Nghi viêm nướu do cao răng','Cạo vôi răng và theo dõi sau 2 tuần',NULL,'Bệnh án đã chốt, chưa xuất hóa đơn để demo tạo hóa đơn',2,'Cao răng mặt trong hàm dưới','Khám tổng quát, cạo vôi răng','2026-07-22 00:00:00',NULL),(5,5,5,3,'2026-07-08 00:00:00','Tái khám sau tẩy trắng','Men răng ổn, hơi ê nhẹ','Theo dõi thêm, hạn chế thực phẩm sậm màu 48 giờ',NULL,'Bệnh án nháp để demo chốt bệnh án',1,'Răng đều màu, không tổn thương mới','Tái khám sau 1 tháng','2026-08-08 00:00:00',NULL);
/*!40000 ALTER TABLE `patientexaminations` ENABLE KEYS */;
UNLOCK TABLES;

